var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아아압!","JPN":"はあああ！","ENG":"Haaah!","TWN":"嚇啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이쪽은 아직 괜찮습니다. 다른 쪽 상황은 어떤가요?","JPN":"こっちはまだ行けます。他のところの状況はどうですか？","ENG":"Things are fine over here. How is everyone else doing?","TWN":"這邊目前還好，另一邊情況如何？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이쪽도 문제없어.","JPN":"こちらも問題ない。","ENG":"I am fine here as well.","TWN":"這邊也沒問題。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"몇 마리 놓치긴 했지만, 성녀가 감당하지 못할 수는 아니야.","JPN":"何匹か逃したが、聖女の手に負えないほどではない。","ENG":"A few monsters got away, but nothing the Saintess cannot handle.","TWN":"雖然放走幾隻，但聖女應該能應付。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그래서 구원자. 지금까지 총 몇 마리를 쓰러트렸지?","JPN":"それで、救世主。今まで何匹倒した？","ENG":"So, Savior. How many have you vanquished so far?","TWN":"所以，救贖者大人目前為止總共擊殺多少隻？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"참고로 난 열 두 마리 째야.","JPN":"ちなみに、私は12匹目だ。","ENG":"I am on my 12th at the moment.","TWN":"順便說一句，我目前已經擊殺12隻。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안. 이번에도 세는 걸 까먹었어.","JPN":"ごめん。今度も数えるのを忘れてたよ。","ENG":"Sorry. I forgot to count again.","TWN":"抱歉，這次又忘記數。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"지휘관이라도 된 양 떠들지 마라, 평민. 넌 내가 시키는 대로만 하면 그만이야.","JPN":"指揮官にでもなったかのように騒ぐな、平民。貴様は私の指示どおりに動いていればいい。","ENG":"Do not yap like you are the commanding officer, peasant. Do as I say, and nothing else.","TWN":"別像個指揮官一樣大呼小叫的，平民。你只要聽我指揮就好。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부상자들은 교대하며 전선을 유지하도록.","JPN":"怪我人は交代し、戦線を維持しろ。","ENG":"The injured are to maintain the line by switching out.","TWN":"傷者輪流上場，守住戰線。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"다음은 없으니, 이곳에서 결판을 지어야 한다!","JPN":"次などない、ここで決着をつけるのだ！","ENG":"There will be no second chance. We need to end this here!","TWN":"沒有下一次的機會，必須在這裡定勝負！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"허억… 허억…","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼…呼呼…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"괜찮으신가요?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"你沒事吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"괘, 괜찮습니다. 아직 싸울 수 있습니다!","JPN":"だ、大丈夫です。まだ戦えます！","ENG":"I-I'm all right. I can still fight!","TWN":"還，還好，還能打！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"부상의 정도가 심합니다. 너무 무리하지 마세요.","JPN":"かなり怪我をされています。あまり無理しないでください。","ENG":"You're severely injured. Don't overdo yourself.","TWN":"你的傷勢很嚴重，不要太勉強自己。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 저희가 약한 탓에 구원자님께 민폐를 끼치는군요.","JPN":"申し訳ありません。俺たちが弱いせいで救世主様にご迷惑をおかけしますね。","ENG":"Forgive us. We're too weak, and nothing but an inconvenience to you.","TWN":"抱歉，都是我們太弱，拖累救贖者大人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그런 말씀 마세요. 여러분들을 지키는 게 구원자로서의 제 사명이니까요.","JPN":"そんなこと言わないでください。皆さんを守るのが、救世主としての僕の使命ですから。","ENG":"Don't say that. It's my duty as the Savior to protect you all.","TWN":"別這麼說。保護大家是我深為救贖者的使命。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…점점 부상자들이 늘고 있어.","JPN":"……どんどん怪我人が増えてる。","ENG":"...More people are getting injured by the minute.","TWN":"…傷者越來越多。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마을에 기사들이 남아있다 해도, 이대로 시간이 끌렸다간 위험할지도 몰라.","JPN":"村に騎士が残っているって言っても、このまま長引くと危ないかもしれない。","ENG":"There are some knights in the village, but it might get dangerous if we keep losing time.","TWN":"就算村莊裡有騎士團，這樣下去時間拉長會有危險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아는… 괜찮겠지?","JPN":"ルクレシアは……大丈夫だよね？","ENG":"I hope... Lucrecia is safe.","TWN":"露可蕾西亞…應該沒問題吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원자님! 큰일입니다!","JPN":"救世主様！　大変です！","ENG":"Savior! There's a problem!","TWN":"救贖者大人！大事不妙！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"남북쪽 방향의 길이 뚫렸습니다. 대장님이 당하셨어요!","JPN":"南北方向の道を突破されました。隊長がやられて！","ENG":"The monsters broke through the southern routes. Our captain is down!","TWN":"南北二邊的路被突圍，隊長也遭到怪獸的攻擊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"다른 쪽은. 전하나 샬롯은 어떻게 되었습니까!","JPN":"他は。殿下やシャーロットはどうなったんですか！","ENG":"What about the other routes? What happened to His Highness, or Carlota?!","TWN":"那其他地方呢？殿下和夏洛特的情況如何？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"그, 그게… 아까부터 통신이 두절입니다.","JPN":"そ、それが……先程から通信が途絶えたままです。","ENG":"W-well... We lost contact with them earlier.","TWN":"這個…從剛才便已失聯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"두 분께서 당하셨을 리는 없겠지만, 이대로 가다간 마을이 위험할 겁니다.","JPN":"お二人が倒れられるはずはないと思いますが、このままでは村が危険です。","ENG":"There is no way that they would've lost, but the village will be in danger if we don't do something.","TWN":"他們二位應該不至於遇難，但這樣下去村莊會有危險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마을에는… 사람들이….","JPN":"村には……みんなが……","ENG":"There are people... in the village...","TWN":"村莊裡…有村民…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 여기서 벗어났다간….","JPN":"でも、ここを離れたら……","ENG":"But if I leave this place...","TWN":"但如果我們撤退…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"막아! 어떻게든 여기서 막아야 한다!","JPN":"止めろ！　何としてもここで止めるんだ！","ENG":"Stop them! Do whatever it takes to stop them here!","TWN":"守住！無論如何都要守住這裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"제기랄. 뭔 놈의 괴수가 끊이질 않는 거야!","JPN":"くそ。なんて数だ！","ENG":"Damn it. There's no end to them!","TWN":"該死，怪獸怎麼來個沒完！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……이럴 때는.","JPN":"……こんな時には。","ENG":"...What...","TWN":"……這種時候。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이럴 때는 어떻게 하면…","JPN":"こんな時には、どうすれば……","ENG":"What do I do, at a time like...","TWN":"這種時候該怎麼辦…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"강하면서 여전히 결단력은 부족하구나. 구원자는.","JPN":"強いくせに、相変わらず優柔不断だな。救世主は。","ENG":"You may be strong, but you still lack decisiveness, Savior.","TWN":"救贖者大人，你雖然能力強，但判斷力還不夠。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이걸로 서른 두 마리 째인가?","JPN":"これで32匹目か？","ENG":"That makes it 32.","TWN":"這是第32隻嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L20_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아무래도 대결의 승리에 한 발짝 가까워진 것 같군.","JPN":"どうやら、対決の勝利に一歩近づいたようだ。","ENG":"I feel one step closer to victory.","TWN":"看來我離勝利又近一步囉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"샬롯? 여긴 어떻게 온 거야?","JPN":"シャーロット？　どうやってここまで？","ENG":"Carlota? How did you make it here?","TWN":"夏洛特？你怎麼會來這裡？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자를 도우라는 전하의 명을 받았어. 내 쪽은 여유가 있었거든.","JPN":"救世主を助けろとの殿下の命があった。私の方は余裕があったからな。","ENG":"His Highness gave me orders to assist the Savior. My side was handled quite easily, you see.","TWN":"殿下命我來幫你，我那邊還游刃有餘。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"다른 쪽에서의 공백은 전하께서 메워주고 계시니, 너무 걱정하지 않아도 돼.","JPN":"他の方面の空白は殿下が埋めてくださっている、あまり心配しなくていい。","ENG":"His Highness is taking care of the other empty areas. So don't worry.","TWN":"另一邊的空缺由殿下補上，不必擔心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안해, 샬롯. 내가 미숙한 탓에 민폐를 끼쳐버렸네.","JPN":"ごめん、シャーロット。僕が未熟で、迷惑をかけちゃったね。","ENG":"I'm sorry, Carlota. I wasn't good enough, and I've caused you trouble.","TWN":"對不起，夏洛特。都怪我還不夠成熟，給你添麻煩。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"동료에게 의지하는 건 부끄러운 일이 아니야.","JPN":"仲間に頼ることは恥ずかしいことではない。","ENG":"It is not embarrassing to lean on your comrades from time to time.","TWN":"依靠同伴並不丟臉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그러니 어서 가. 구원자.","JPN":"だから早く行け。救世主。","ENG":"Now go, Savior.","TWN":"你快去吧，救贖者大人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전투 도중 기사가 등을 보이는 건 수치스러운 행위지만…","JPN":"戦闘中に騎士が背を見せるのは恥ずかしい行為だが……","ENG":"It is dishonorable for a knight to turn their back during battle, but...","TWN":"雖然騎士在作戰中背對敵人是可恥的行為…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이번만큼은 내가, 구원자의 등을 가려줄 테니까.","JPN":"今は私が、救世主の背を隠してやる。","ENG":"I have your back this time.","TWN":"但這次我會掩護你的背。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"응. 고마워, 샬롯.","JPN":"うん。ありがとう、シャーロット。","ENG":"Okay. Thank you, Carlota.","TWN":"嗯。謝謝你，夏洛特。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"뒤는 부탁할게.","JPN":"後は頼むね。","ENG":"I'll leave the rest to you.","TWN":"後面交給你了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그래. 걱정 말고 가, 구원자.","JPN":"うん。心配しないで行け、救世主。","ENG":"Yes. So leave all your worries behind and go, Savior.","TWN":"好，不用擔心，救贖者大人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"선봉의 깃발은 늘 그랬듯.","JPN":"先鋒の旗はいつものように。","ENG":"As always, I will be the one...","TWN":"我會像以往一樣，揹著前鋒的旗幟，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"내가 짊어지고 나아갈 테니.","JPN":"私が背負って進むから。","ENG":"to carry the banner of the vanguard.","TWN":"前進。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_SEASON2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"}]`);export{e as default};